def main(args):
    import json

    topic = args.params.get('topic', 'Content')
    blog_post = args.params.get('blog_post', '')
    social_posts_raw = args.params.get('social_posts', '{}')
    analysis_raw = args.params.get('analysis', '{}')

    # Parse JSON inputs
    try:
        if isinstance(social_posts_raw, str):
            # Try to extract JSON from markdown code blocks
            cleaned = social_posts_raw.replace('```json', '').replace('```', '').strip()
            social_posts = json.loads(cleaned) if '{' in cleaned else {}
        else:
            social_posts = social_posts_raw
    except:
        social_posts = {'twitter': 'N/A', 'linkedin': 'N/A', 'instagram': 'N/A'}

    try:
        analysis = json.loads(analysis_raw) if isinstance(analysis_raw, str) else analysis_raw
    except:
        analysis = {'hashtags': [], 'seo_score': 0, 'recommendations': []}

    # Build beautiful formatted output
    output = f"""
╔═════════════════════════════════════╗
║ 🚀 VIRAL CONTENT PACKAGE READY 🚀  ║
║  Topic: {topic.upper()[:45]:^45}    ║
╚═════════════════════════════════════╝

━━━━━━━━━━━━━━━━━━━━
📝 BLOG POST
━━━━━━━━━━━━━━━━━━━━

{blog_post}


━━━━━━━━━━━━━━━━━━━━
📱 SOCIAL MEDIA POSTS
━━━━━━━━━━━━━━━━━━━━

🐦 TWITTER/X:
{'-' * 7}
{social_posts.get('twitter', 'N/A')}

💼 LINKEDIN:
{'-' * 7}
{social_posts.get('linkedin', 'N/A')}

📸 INSTAGRAM:
{'-' * 7}
{social_posts.get('instagram', 'N/A')}


━━━━━━━━━━━━━━━━━━━━
#️⃣ HASHTAG STRATEGY
━━━━━━━━━━━━━━━━━━━━

{' '.join(analysis.get('hashtags', [])[:12])}


━━━━━━━━━━━━━━━━━━━━
📊 SEO ANALYSIS
━━━━━━━━━━━━━━━━━━━━

📈 SEO Score: {analysis.get('seo_score', 0)}/100
📝 Word Count: {analysis.get('word_count', 0)} words
🔑 Top Keywords: {', '.join(analysis.get('top_keywords', [])[:5])}

📋 Meta Description:
{analysis.get('meta_description', 'N/A')}

✅ Recommendations:
"""

    for rec in analysis.get('recommendations', []):
        output += f"   {rec}\n"

    output += """

━━━━━━━━━━━━━━━━━━━━
🎯 NEXT STEPS
━━━━━━━━━━━━━━━━━━━━

1. 📝 Publish blog post to your website/Medium
2. 🐦 Schedule Twitter thread for maximum engagement time
3. 💼 Post on LinkedIn during business hours
4. 📸 Create visual for Instagram post
5. 🔗 Cross-promote across all platforms
6. 📊 Track engagement metrics
7. 💬 Respond to comments within first hour

✨ Content package generated with AI-powered workflow ✨
"""

    return {'final_package': output}

